import { useEffect, useState } from "react";
import { Link } from "react-router-dom";

function Dashboard() {
  const [questions, setQuestions] = useState([]);
  const [filter, setFilter] = useState("recent");
  const [category, setCategory] = useState("all");

  // FETCH QUESTIONS
  useEffect(() => {
    fetch("http://localhost:5000/api/questions")
      .then((res) => res.json())
      .then((data) => setQuestions(data))
      .catch((err) => console.log(err));
  }, []);

  // FILTER + SORT
  const filtered = questions
    .filter((q) => (category === "all" ? true : q.category === category))
    .sort((a, b) => {
      if (filter === "recent") {
        return new Date(b.createdAt) - new Date(a.createdAt);
      }
      return 0;
    });

  return (
    <>
      {/* HEADER */}
      <div className="header">
        <div>
          <h2>All Posts</h2>
          <p>{filtered.length} posts available</p>
        </div>

        <Link to="/ask" className="new-post">
          + New Post
        </Link>
      </div>

      {/* POSTS */}
      {filtered.length === 0 ? (
        <p>No posts available</p>
      ) : (
        filtered.map((q) => (
          <div key={q._id} className="post">

            <div className="post-top">
              <div className="user">
                <div className="avatar small">
                  {q.postedBy?.[0]?.toUpperCase() || "U"}
                </div>
                <div>
                  <b>{q.postedBy || "Unknown"}</b>
                  <p style={{ margin: 0, fontSize: "12px" }}>{q.role}</p>
                </div>
              </div>

              <span className="tag">{q.category}</span>
            </div>

            <h3>{q.title}</h3>

            <div className="post-bottom">
              <span className="like-btn">
                ❤️ {q.likes?.length || 0}
              </span>

              <Link to={`/answers/${q._id}`} className="view-btn">
                View →
              </Link>
            </div>

          </div>
        ))
      )}
    </>
  );
}

export default Dashboard;
